// Create Notion page with blocks
const page = await notion.pages.create({
  parent: { database_id: "database-id" },
  properties: {
    Title: { title: [{ text: { content: "New Page" } }] },
  },
  children: [
    {
      object: "block",
      type: "paragraph",
      paragraph: { rich_text: [{ text: { content: "Page content" } }] },
    },
  ],
});

